import pytest

def test_deep_get_happy_path():
    """Test basic nested dictionary access with dot notation."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }
    assert deep_get(data, 'a.b.c') == 42
    assert deep_get(data, 'a.b') == {'c': 42}
    assert deep_get(data, 'a') == {'b': {'c': 42}}

def test_deep_get_with_default():
    """Test returning default value when key doesn't exist."""
    data = {'a': {'b': 1}}
    assert deep_get(data, 'a.c', 'default') == 'default'
    assert deep_get(data, 'x.y.z', 'not_found') == 'not_found'
    assert deep_get(data, 'a.b.c', 0) == 0

def test_deep_get_with_none_default():
    """Test default None behavior when key doesn't exist."""
    data = {'a': {'b': 1}}
    assert deep_get(data, 'a.c') is None
    assert deep_get(data, 'x.y.z') is None

def test_deep_get_empty_keys():
    """Test with empty keys string."""
    data = {'a': 1}
    assert deep_get(data, '') == data
    assert deep_get(data, '', 'default') == data

def test_deep_get_single_key():
    """Test with single key (no nesting)."""
    data = {'a': 1, 'b': 2}
    assert deep_get(data, 'a') == 1
    assert deep_get(data, 'b') == 2
    assert deep_get(data, 'c', 'default') == 'default'

def test_deep_get_non_dict_intermediate():
    """Test when intermediate value is not a dict."""
    data = {'a': 1, 'b': {'c': 2}}
    assert deep_get(data, 'a.b') is None
    assert deep_get(data, 'a.b', 'default') == 'default'
    assert deep_get(data, 'b.c') == 2

def test_deep_get_with_list_values():
    """Test when dictionary contains lists."""
    data = {
        'a': [
            {'b': 1},
            {'b': 2}
        ]
    }
    # This should return None since we can't index into list with string key
    assert deep_get(data, 'a.0') is None
    assert deep_get(data, 'a.0.b') is None

def test_deep_get_with_special_characters():
    """Test with keys containing special characters."""
    data = {
        'a.b': {
            'c.d': 42
        }
    }
    assert deep_get(data, 'a.b.c.d') is None
    assert deep_get(data, 'a\\.b.c\\.d') == 42  # This would require escaping

def test_deep_get_with_none_values():
    """Test when dictionary contains None values."""
    data = {
        'a': None,
        'b': {
            'c': None
        }
    }
    assert deep_get(data, 'a.b') is None
    assert deep_get(data, 'b.c') is None
    assert deep_get(data, 'b.c.d', 'default') == 'default'

def test_deep_get_with_empty_dict():
    """Test with empty dictionary."""
    data = {}
    assert deep_get(data, 'a.b.c') is None
    assert deep_get(data, 'a', 'default') == 'default'

def test_deep_get_with_non_dict_input():
    """Test when input is not a dictionary."""
    assert deep_get(None, 'a.b') is None
    assert deep_get(42, 'a.b') is None
    assert deep_get([1, 2, 3], '0') is None
    assert deep_get("string", 'length') is None
    assert deep_get(True, 'value') is None

def test_deep_get_with_whitespace_keys():
    """Test with keys containing whitespace."""
    data = {
        ' a ': {
            ' b ': 42
        }
    }
    assert deep_get(data, ' a . b ') is None
    assert deep_get(data, ' a .b ') is None
    assert deep_get(data, 'a.b') is None  # Different keys due to whitespace
